  1→import type {
  2→  SDUIContext,
  3→  SDUIRule,
  4→  SDUILogicOperand,
  5→  SDUIVarOperator,
  6→  SDUILogicPrimitive,
  7→} from '../models';
  8→import { resolveContextPath } from './interpolation';
  9→
 10→function isVarOperator(operand: SDUILogicOperand): operand is SDUIVarOperator {
 11→  return (
 12→    operand !== null &&
 13→    typeof operand === 'object' &&
 14→    'var' in operand &&
 15→    typeof (operand as SDUIVarOperator).var === 'string'
 16→  );
 17→}
 18→
 19→function isPrimitive(value: unknown): value is SDUILogicPrimitive {
 20→  return (
 21→    value === null ||
 22→    typeof value === 'string' ||
 23→    typeof value === 'number' ||
 24→    typeof value === 'boolean'
 25→  );
 26→}
 27→
 28→function resolveOperand(
 29→  operand: SDUILogicOperand,
 30→  context: SDUIContext,
 31→): SDUILogicPrimitive {
 32→  if (isPrimitive(operand)) return operand;
 33→  if (isVarOperator(operand)) {
 34→    const resolved = resolveContextPath(context, operand.var);
 35→    if (isPrimitive(resolved)) return resolved;
 36→    return null;
 37→  }
 38→  return evaluateRule(operand as SDUIRule, context);
 39→}
 40→
 41→function evaluateComparison(
 42→  operator: string,
 43→  operands: [SDUILogicOperand, SDUILogicOperand],
 44→  context: SDUIContext,
 45→): boolean {
 46→  const left = resolveOperand(operands[0], context);
 47→  const right = resolveOperand(operands[1], context);
 48→
 49→  switch (operator) {
 50→    case '==':
 51→      return left == right; // eslint-disable-line eqeqeq
 52→    case '!=':
 53→      return left != right; // eslint-disable-line eqeqeq
 54→    case '>':
 55→      return (left as number) > (right as number);
 56→    case '<':
 57→      return (left as number) < (right as number);
 58→    case '>=':
 59→      return (left as number) >= (right as number);
 60→    case '<=':
 61→      return (left as number) <= (right as number);
 62→    default:
 63→      return false;
 64→  }
 65→}
 66→
 67→export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
 68→  if (!rule || typeof rule !== 'object') return false;
 69→
 70→  const keys = Object.keys(rule);
 71→  if (keys.length === 0) return false;
 72→
 73→  const operator = keys[0];
 74→  const operands = (rule as Record<string, unknown>)[operator];
 75→
 76→  if (operator === 'and') {
 77→    if (!Array.isArray(operands)) return false;
 78→    return (operands as SDUIRule[]).every(sub => evaluateRule(sub, context));
 79→  }
 80→
 81→  if (operator === 'or') {
 82→    if (!Array.isArray(operands)) return false;
 83→    return (operands as SDUIRule[]).some(sub => evaluateRule(sub, context));
 84→  }
 85→
 86→  if (operator === '!') {
 87→    return !evaluateRule(operands as SDUIRule, context);
 88→  }
 89→
 90→  const comparisonOps = ['==', '!=', '>', '<', '>=', '<='];
 91→  if (comparisonOps.includes(operator)) {
 92→    if (!Array.isArray(operands) || operands.length !== 2) return false;
 93→    return evaluateComparison(
 94→      operator,
 95→      operands as [SDUILogicOperand, SDUILogicOperand],
 96→      context,
 97→    );
 98→  }
 99→
100→  return false;
101→}
